def solve(events):
    if not events:
        return []

    bookings = []
    for event in events:
        if 'vc_room' in event and event['vc_room']:
            booking_details = {
                'title': event.get('title', 'No Title'),
                'start_time': event.get('start_time', 'No Start Time'),
                'end_time': event.get('end_time', 'No End Time'),
                'vc_room': event['vc_room'],
            }
            bookings.append(booking_details)

    return bookings
